	(318, '사내 보안 캠페인 및 PC 보안 점검 안내', 1, '2026-02-23', '답변완료', '임직원 여러분, 안녕하세요. 개발팀입니다.\n최근 기승을 부리는 피싱 메일 및 보안 사고를 예방하고자 6월 정기 PC 보안 점검을 실시합니다.\n 업무에 차질 없도록 아래 내용을 확인하여 협조 부탁드립니다.', NULL, 0, 'N', 41, NULL, 9999, NULL, NULL),
	(319, '경영 게시판 글쓰기 권한을 요청드립니다.', 3, '2026-02-23', '일반', '해당 게시판의 글쓰기 권한을 요청 드립니다.\r\n경영 부서 부장 유다빈.', NULL, 0, 'Y', 7, NULL, 7777, NULL, NULL),
	(320, '사내 네트워킹 데이 "랜덤 런치" 모집', 1, '2026-02-23', '답변완료', '안녕하세요! 인사팀입니다.\r\n타 부서 동료들과 가볍게 소통하며 맛있는 점심을 즐길 수 있는 제 1회 랜덤 런치를 개최합니다. \r\n이번 달은 어떤 동료와 짝이 될지 기대하며 많은 신청 바랍니다!', NULL, 3, 'N', 21, NULL, 9999, NULL, NULL),
	(321, '임직원 건강검진 실시 안내', 1, '2026-02-23', '답변완료', '안녕하세요, 인사팀입니다.\r\n회사는 임직원 여러분의 건강한 직장 생활을 응원합니다. \r\n올해 상반기 건강검진 일정을 아래와 같이 안내드리오니, 기한 내에 예약 및 검진을 완료해 주시기 바랍니다.', NULL, 1, 'N', 20, NULL, 9999, NULL, NULL),
	(325, '문의게시판 작동하는지 문의드립니다.', 4, '2026-02-23', '삭제글', '이거 제대로 동작하나요?\n\n그리고 위에 글쓰기 할 때 태그는 어디다 쓰나요? 일반 밖에 없는데?\n\n태그 저거 지워야 하는 거 아닌가요?', NULL, 0, 'Y', 15, NULL, 7777, NULL, NULL),
	(328, '회사 재정 상황 보고서 관련', 4, '2026-02-23', '일반', '이번 분기 재정 적자가 심각한 상황인데\r\n대책 있는 사람 없습니까?\r\n\r\n또 뭐 새로운 거 개발해서 대박 나면 빚 다 갚는다는 그런 소리 하지 말고', NULL, 0, 'N', 1, NULL, 2003, NULL, NULL),
	(329, '게시글 관련', 4, '2026-02-23', '일반', '페이징을 10개를 너무 많ㅇ ㅣ줬다 \r\n한 다섯개만 주는 건데', NULL, 0, 'N', 1, NULL, 2003, NULL, NULL),
